DisplayManager::DisplayManager(LogManager& logger, uint8_t clk, uint8_t mosi, uint8_t cs, uint8_t rst)
    : logger_(logger), u8g2_(U8G2_R0, clk, mosi, cs, rst) {}

void DisplayManager::begin(uint8_t contrast) {
  u8g2_.begin();
  u8g2_.setContrast(contrast);
  u8g2_.setFont(u8g2_font_6x12_tf);
  logger_.info("ST7920 display initialized in 3-wire serial mode");
}

String DisplayManager::fit(const String& text, size_t maxLen) {
  if (text.length() <= maxLen) return text;
  return text.substring(0, maxLen);
}

void DisplayManager::drawHeader(const String& title) {
  u8g2_.clearBuffer();
  u8g2_.drawFrame(0, 0, 128, 64);
  u8g2_.drawBox(0, 0, 128, 12);
  u8g2_.setDrawColor(0);
  u8g2_.drawStr(4, 10, title.c_str());
  u8g2_.setDrawColor(1);
}

void DisplayManager::drawHeaderBar(const String& text) {
  u8g2_.clearBuffer();
  u8g2_.drawFrame(0, 0, 128, 64);
  u8g2_.drawBox(0, 0, 128, 12);
  u8g2_.setDrawColor(0);
  const String header = fit(text, 20);
  u8g2_.drawStr(2, 10, header.c_str());
  u8g2_.setDrawColor(1);
}

void DisplayManager::showLogo() {
  u8g2_.clearBuffer();
  u8g2_.drawXBMP(0, 0, 128, 64, epd_bitmap_LCD_LOGO);
  u8g2_.sendBuffer();
}

void DisplayManager::showBoot(const String& deviceName) {
  drawHeader("CT-100");
  u8g2_.drawStr(4, 24, "Start systemu");
  u8g2_.drawStr(4, 38, fit(deviceName, 20).c_str());
  u8g2_.drawStr(4, 52, "ETH + RFID + TCP");
  u8g2_.sendBuffer();
}

void DisplayManager::showStatus(const String& line1, const String& line2, const String& line3, const String& line4) {
  drawHeader("Status");
  u8g2_.drawStr(4, 24, fit(line1, 20).c_str());
  u8g2_.drawStr(4, 36, fit(line2, 20).c_str());
  u8g2_.drawStr(4, 48, fit(line3, 20).c_str());
  u8g2_.drawStr(4, 60, fit(line4, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showInfo(const String& title,
                              const String& line1,
                              const String& line2,
                              const String& line3,
                              const String& line4) {
  drawHeader(fit(title, 18));
  u8g2_.drawStr(4, 24, fit(line1, 20).c_str());
  u8g2_.drawStr(4, 36, fit(line2, 20).c_str());
  u8g2_.drawStr(4, 48, fit(line3, 20).c_str());
  u8g2_.drawStr(4, 60, fit(line4, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showCard(const String& card) {
  drawHeader("RFID");
  u8g2_.drawStr(4, 24, "Odczyt karty:");
  u8g2_.drawStr(4, 40, fit(card, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showTcp(const String& message) {
  drawHeader("TCP");
  u8g2_.drawStr(4, 24, "Komunikat:");
  u8g2_.drawStr(4, 40, fit(message, 20).c_str());
  u8g2_.drawStr(4, 54, fit(message.substring(20), 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showIdleWeight(const String& header, const String& weight, const String& prompt) {
  drawHeaderBar(header);

  u8g2_.setFont(u8g2_font_6x12_tf);
  u8g2_.drawStr(4, 24, "Aktualna waga:");

  String w = fit(weight, 18);
  u8g2_.setFont(u8g2_font_10x20_tf);
  u8g2_.drawStr(4, 46, w.c_str());

  u8g2_.setFont(u8g2_font_6x12_tf);
  u8g2_.drawStr(4, 60, fit(prompt, 20).c_str());

  u8g2_.sendBuffer();
}

void DisplayManager::showRfidPrompt(const String& title, const String& line1, const String& line2) {
  drawHeader(fit(title, 18));
  u8g2_.drawFrame(6, 18, 22, 16);
  u8g2_.drawFrame(10, 22, 14, 8);
  u8g2_.drawStr(34, 28, fit(line1, 15).c_str());
  u8g2_.drawStr(4, 52, fit(line2, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showInputScreen(const String& title, const String& value, const String& hint) {
  drawHeader(fit(title, 18));
  u8g2_.drawStr(4, 22, "Wprowadz:");
  u8g2_.drawFrame(4, 28, 120, 16);
  u8g2_.drawStr(8, 40, fit(value, 16).c_str());
  u8g2_.drawStr(4, 58, fit(hint, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showSummaryScreen(const String& line1, const String& line2, const String& line3, const String& line4) {
  drawHeader("Podsumowanie");
  u8g2_.drawStr(4, 22, fit(line1, 20).c_str());
  u8g2_.drawStr(4, 34, fit(line2, 20).c_str());
  u8g2_.drawStr(4, 46, fit(line3, 20).c_str());
  u8g2_.drawStr(4, 58, fit(line4, 20).c_str());
  u8g2_.sendBuffer();
}

void DisplayManager::showResultScreen(const String& title, const String& line1, const String& line2) {
  drawHeader(fit(title, 18));
  u8g2_.drawStr(4, 28, fit(line1, 20).c_str());
  u8g2_.drawStr(4, 46, fit(line2, 20).c_str());
  u8g2_.sendBuffer();
}
